import { withDb } from "./db.mjs";

const RULES = {
  invoiceHighCents: 2_500_000,
  usageDropFraction: 0.30,
  qualifyingTiers: ["strategic", "enterprise"],
  highSupportSeverities: ["high", "critical"],
  escalationStatus: "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  monitorStatus: "Monitoring — no escalation required."
};

const OWNER_FOR_CATEGORY = {
  regulatory: "Legal",
  invoice: "Finance",
  shipment: "Customer Success",
  usage: "Customer Success",
  support: "Support"
};
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = {
  regulatory: "Regulatory hold",
  invoice: "Overdue invoice",
  shipment: "Delayed shipment",
  support: "Escalated support",
  usage: "Usage decline"
};

function evaluateRisks(world, now) {
  const nowMs = Date.parse(now);
  const fired = {};

  const overdueInvoice = (world.invoices || []).find(
    (inv) => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= RULES.invoiceHighCents
  );
  if (overdueInvoice) fired.invoice = true;

  const lateShipment = (world.shipments || []).find(
    (sh) => !sh.deliveredDate && Date.parse(sh.slaDate) < nowMs
  );
  if (lateShipment) fired.shipment = true;

  const openReg = (world.regulatoryFlags || []).find((flag) => flag.status === "open");
  if (openReg) fired.regulatory = true;

  const escalatedSupport = (world.supportCases || []).find(
    (c) => c.status === "open" && RULES.highSupportSeverities.includes(c.severity)
  );
  if (escalatedSupport) fired.support = true;

  const usage = world.usage || {};
  if (
    typeof usage.priorPeriodUnits === "number" &&
    typeof usage.currentPeriodUnits === "number" &&
    usage.priorPeriodUnits > 0 &&
    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - RULES.usageDropFraction)
  ) {
    fired.usage = true;
  }

  return fired;
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const row = (await client.query("SELECT doc FROM accounts LIMIT 1")).rows[0];
    const doc = row.doc;
    const world = {
      account: { accountId: doc._id, name: doc.name, tier: doc.tier, region: doc.region },
      invoices: doc.invoices,
      shipments: doc.shipments,
      regulatoryFlags: doc.regulatoryFlags,
      supportCases: doc.supportCases,
      usage: doc.usage
    };

    const fired = evaluateRisks(world, now);
    const signals = SIGNAL_ORDER.filter((cat) => fired[cat]).map((cat) => ({ category: cat, name: SIGNAL_NAME[cat] }));

    const tierOk = RULES.qualifyingTiers.includes(String(world.account.tier || "").toLowerCase());
    const q = tierOk && signals.length >= 1;

    const ownersSet = new Set(Object.keys(fired).map((cat) => OWNER_FOR_CATEGORY[cat]));
    const owners = q ? OWNER_ORDER.filter((o) => ownersSet.has(o)) : [];

    const status = q ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signals.length} signals: ${signals.map((s) => s.name).join(", ")}`;
    const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";

    const accountId = world.account.accountId;
    const requestId = doc.request?.requestId || "req-unknown";

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [accountId]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, "Strategic Account Rescue", status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} recovery review`, now, "open"]
      );
    }

    const customerMsg = q
      ? `Your account has been identified as requiring priority attention. Our team has detected ${signals.length} active concern${signals.length > 1 ? "s" : ""} — ${signals.map((s) => s.name).join(", ")} — and a dedicated recovery team has been assigned to work with you. You will be contacted shortly with next steps and a resolution timeline.`
      : "Your account is in good standing and is being monitored under our standard process. No escalation is required at this time.";

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, accountId, customerMsg]
    );

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, `Rescue workflow completed. ${riskSummary}. Status: ${status}`, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
