import { withDb } from "./db.mjs";

const RULES = {
  invoiceHighCents: 2_500_000,
  usageDropFraction: 0.3,
  qualifyingTiers: ["strategic", "enterprise"],
  highSupportSeverities: ["high", "critical"],
  escalationStatus: "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  monitorStatus: "Monitoring — no escalation required."
};

const OWNER_FOR_CATEGORY = {
  regulatory: "Legal",
  invoice: "Finance",
  shipment: "Customer Success",
  usage: "Customer Success",
  support: "Support"
};

const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = {
  regulatory: "Regulatory hold",
  invoice: "Overdue invoice",
  shipment: "Delayed shipment",
  support: "Escalated support",
  usage: "Usage decline"
};

function evaluateRisks(doc, now) {
  const nowMs = Date.parse(now);
  const fired = {};

  const overdueInvoice = (doc.invoices || []).find(
    (inv) => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= RULES.invoiceHighCents
  );
  if (overdueInvoice) fired.invoice = true;

  const lateShipment = (doc.shipments || []).find((shipment) => !shipment.deliveredDate && Date.parse(shipment.slaDate) < nowMs);
  if (lateShipment) fired.shipment = true;

  const openRegulatoryFlag = (doc.regulatoryFlags || []).find((flag) => flag.status === "open");
  if (openRegulatoryFlag) fired.regulatory = true;

  const escalatedSupport = (doc.supportCases || []).find(
    (c) => c.status === "open" && RULES.highSupportSeverities.includes(c.severity)
  );
  if (escalatedSupport) fired.support = true;

  const usage = doc.usage || {};
  if (
    typeof usage.priorPeriodUnits === "number" &&
    typeof usage.currentPeriodUnits === "number" &&
    usage.priorPeriodUnits > 0 &&
    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - RULES.usageDropFraction)
  ) {
    fired.usage = true;
  }

  return fired;
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const row = (await client.query("SELECT doc FROM accounts LIMIT 1")).rows[0];
    const doc = row.doc;

    const accountId = doc._id;
    const requestId = doc.request?.requestId || `req-${accountId}`;
    const title = doc.request?.title || "Strategic account rescue";
    const fired = evaluateRisks(doc, now);
    const signals = SIGNAL_ORDER.filter((category) => fired[category]).map((category) => SIGNAL_NAME[category]);

    const tierOk = RULES.qualifyingTiers.includes(String(doc.tier || "").toLowerCase());
    const qualifies = tierOk && signals.length > 0;
    const owners = qualifies
      ? OWNER_ORDER.filter((owner) => Object.keys(fired).some((category) => OWNER_FOR_CATEGORY[category] === owner))
      : [];
    const status = qualifies ? RULES.escalationStatus : RULES.monitorStatus;
    const nextStep = qualifies ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
    const dueAt = new Date(now).toISOString();

    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    await client.query(
      `INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary)
       VALUES ($1, $2, $3, $4, $5, $6)`,
      [requestId, accountId, title, status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        `INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [requestId, accountId, owner, `${owner} recovery review`, dueAt, "open"]
      );
    }

    const customerMessage = qualifies
      ? `Your account has been flagged for priority attention by our executive recovery team. We have identified ${signals.length} active risk area${
          signals.length === 1 ? "" : "s"
        } that require immediate resolution. A dedicated recovery owner has been assigned and will be in touch shortly to coordinate next steps and ensure your service continuity is maintained.`
      : "Your account is currently being monitored under standard protocols. No escalation is required at this time. Our team will continue to track your account health and will reach out if any action becomes necessary.";

    await client.query(
      `INSERT INTO customer_messages (request_id, account_id, body)
       VALUES ($1, $2, $3)`,
      [requestId, accountId, customerMessage]
    );

    await client.query(
      `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
       VALUES ($1, $2, $3, $4, $5)`,
      [requestId, accountId, `Rescue workflow initiated. ${status}`, dueAt, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}

